import React, { useEffect, useRef } from 'react';
import { ParticleEffectType } from '../types';

interface Props {
  type: ParticleEffectType;
  color: string;
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  life: number;
  maxLife: number;
  noiseOffset: number;
  pulseOffset: number;
  opacity: number;
  sparkleSpeed: number;
}

const AtmosphereOverlay: React.FC<Props> = ({ type, color }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particles = useRef<Particle[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    const createParticle = (isInitial: boolean = false): Particle => {
      const isMist = type === 'MIST';
      const isFrost = type === 'FROST';

      return {
        x: Math.random() * canvas.width,
        y: isInitial ? Math.random() * canvas.height : (Math.random() * canvas.height * 0.5) - 50,
        vx: (Math.random() - 0.5) * 0.4,
        vy: isFrost ? (Math.random() * 0.5 + 0.2) : (Math.random() * 0.3 + 0.1),
        size: Math.random() * 1.5 + 0.2, // 极小尺寸，营造精致感
        life: isInitial ? Math.random() * 1000 : 0,
        maxLife: Math.random() * 1000 + 1000,
        noiseOffset: Math.random() * 1000,
        pulseOffset: Math.random() * Math.PI * 2,
        opacity: Math.random() * 0.5 + 0.2,
        sparkleSpeed: Math.random() * 0.02 + 0.005
      };
    };

    // 粒子密度
    const count = type === 'HOLY_LIGHT' ? 150 : 200;
    particles.current = Array.from({ length: count }, () => createParticle(true));

    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const time = Date.now();

      ctx.globalCompositeOperation = 'lighter'; // 使用叠加模式增强发光感

      particles.current.forEach((p, i) => {
        p.life++;

        // 核心动力学：缓慢的飘落与水平晃动
        p.y += p.vy;
        p.x += p.vx + Math.sin(time * 0.001 + p.noiseOffset) * 0.3;

        if (p.life >= p.maxLife || p.y > canvas.height + 20) {
          particles.current[i] = createParticle(false);
          return;
        }

        // 呼吸式透明度
        const lifeRatio = Math.sin((p.life / p.maxLife) * Math.PI);
        const twinkle = (Math.sin(time * p.sparkleSpeed + p.pulseOffset) + 1) / 2;
        const currentOpacity = p.opacity * lifeRatio * (0.3 + twinkle * 0.7);

        ctx.fillStyle = color;

        if (type === 'FROST') {
          // 霜雪粒子：细长形
          ctx.save();
          ctx.translate(p.x, p.y);
          ctx.rotate(Math.PI / 4);
          ctx.globalAlpha = currentOpacity;
          ctx.fillRect(-p.size/2, -p.size*2, p.size, p.size*4);
          ctx.restore();
        } else if (type === 'MIST' || type === 'FIREFLY') {
          // 迷雾/萤火：软边缘模糊感
          const gradient = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size * 6);
          gradient.addColorStop(0, `${color}${Math.floor(currentOpacity * 255).toString(16).padStart(2, '0')}`);
          gradient.addColorStop(1, 'transparent');
          ctx.fillStyle = gradient;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.size * 6, 0, Math.PI * 2);
          ctx.fill();
        } else {
          // 默认：星芒闪烁感 (Glimmer)
          ctx.globalAlpha = currentOpacity;

          // 绘制一个微小的十字星芒
          const s = p.size * (0.5 + twinkle * 1.5);
          ctx.beginPath();
          ctx.moveTo(p.x - s*2, p.y);
          ctx.lineTo(p.x + s*2, p.y);
          ctx.moveTo(p.x, p.y - s*2);
          ctx.lineTo(p.x, p.y + s*2);
          ctx.strokeStyle = color;
          ctx.lineWidth = 0.5;
          ctx.stroke();

          ctx.beginPath();
          ctx.arc(p.x, p.y, s, 0, Math.PI * 2);
          ctx.fill();
        }
      });

      animationFrame = requestAnimationFrame(render);
    };

    render();
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrame);
    };
  }, [type, color]);

  return <canvas ref={canvasRef} className="absolute inset-0 pointer-events-none z-20" />;
};

export default AtmosphereOverlay;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GODDESS_DATA } from './constants';
import { Goddess } from './types';
import ButterflyOverlay from './components/ButterflyOverlay';
import PetalOverlay from './components/PetalOverlay';
import AtmosphereOverlay from './components/AtmosphereOverlay';
import SelectionBar from './components/SelectionBar';
import LocalAssetManager from './components/LocalAssetManager';
import InfoOverlay from './components/InfoOverlay';

type ActiveView = 'GODDESS' | 'ANGEL';
type InfoSection = 'NONE' | 'ABOUT' | 'NOTICE' | 'CUSTOM' | 'CONTACT';

const App: React.FC = () => {
  const [goddesses, setGoddesses] = useState<Goddess[]>(GODDESS_DATA);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showDetail, setShowDetail] = useState(false);
  const [showManager, setShowManager] = useState(false);
  const [activeView, setActiveView] = useState<ActiveView>('GODDESS');
  const [activeInfo, setActiveInfo] = useState<InfoSection>('NONE');
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 });

  const selectedGoddess = goddesses[currentIndex];
  const isTransitioningRef = useRef(false);

  const performChange = useCallback((newIndex: number) => {
    if (isTransitioningRef.current) return;

    setIsTransitioning(true);
    isTransitioningRef.current = true;
    setShowDetail(false); 

    setTimeout(() => {
      setCurrentIndex(newIndex);
      setTimeout(() => {
        setIsTransitioning(false);
        isTransitioningRef.current = false;
      }, 50);
    }, 800);
  }, []);

  const handleGoddessChange = useCallback((g: Goddess) => {
    const newIndex = goddesses.findIndex(item => item.id === g.id);
    if (newIndex === currentIndex) return;
    performChange(newIndex);
  }, [currentIndex, goddesses, performChange]);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({
        x: e.clientX / window.innerWidth,
        y: e.clientY / window.innerHeight,
      });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  useEffect(() => {
    const handleWheel = (e: WheelEvent) => {
      if (activeInfo !== 'NONE' || activeView !== 'GODDESS' || isTransitioningRef.current) return;
      if (Math.abs(e.deltaY) < 15) return;

      if (e.deltaY > 0) {
        const nextIndex = (currentIndex + 1) % goddesses.length;
        performChange(nextIndex);
      } else {
        const prevIndex = (currentIndex - 1 + goddesses.length) % goddesses.length;
        performChange(prevIndex);
      }
    };

    window.addEventListener('wheel', handleWheel, { passive: true });
    return () => window.removeEventListener('wheel', handleWheel);
  }, [currentIndex, goddesses.length, activeView, activeInfo, performChange]);

  const handleViewChange = (view: ActiveView) => {
    if (view === activeView || isTransitioningRef.current) return;
    setIsTransitioning(true);
    isTransitioningRef.current = true;
    setShowDetail(false);
    setTimeout(() => {
      setActiveView(view);
      setActiveInfo('NONE');
      setTimeout(() => {
        setIsTransitioning(false);
        isTransitioningRef.current = false;
      }, 50);
    }, 700);
  };

  const updateLocalUrl = (id: string, url: string) => {
    setGoddesses(prev => prev.map(g => g.id === id ? { ...g, localUrl: url } : g));
  };

  const isHundredFlowers = selectedGoddess.id === 'hundred-flowers';

  return (
    <div className={`relative w-screen h-screen transition-all duration-[1200ms] ${activeView === 'GODDESS' ? 'bg-[#050505]' : 'bg-[#08080a]'} text-[#e5e5e5] overflow-hidden select-none font-serif`}>
      {/* 装饰边框 */}
      <div className="absolute inset-16 border border-white/[0.03] pointer-events-none z-40 transition-opacity duration-1000" />

      {/* 背景层 */}
      <div className={`absolute inset-0 z-10 transition-all duration-[1500ms] ease-in-out ${isTransitioning ? 'opacity-0 scale-105 blur-2xl' : 'opacity-100 scale-100 blur-0'}`}>
        <div className="relative w-full h-full overflow-hidden">
          <div 
            className="w-full h-full transition-transform duration-[8000ms] ease-out"
            style={{ transform: `scale(1.1) translate(${(mousePos.x - 0.5) * -30}px, ${(mousePos.y - 0.5) * -30}px)` }}
          >
            {activeView === 'GODDESS' ? (
              <img 
                key={selectedGoddess.localUrl || selectedGoddess.image}
                src={selectedGoddess.localUrl || selectedGoddess.image} 
                alt={selectedGoddess.name} 
                className={`w-full h-full object-cover transition-opacity duration-[2000ms] ${isHundredFlowers ? 'opacity-70' : 'opacity-50'}`}
              />
            ) : (
              <div className="w-full h-full bg-[#0c0c10]" />
            )}
          </div>
          <div className="absolute inset-0 vignette pointer-events-none" />
        </div>
      </div>

      {/* 粒子/环境层 */}
      <div className={`relative z-20 transition-opacity duration-1000 ${isTransitioning ? 'opacity-0' : 'opacity-100'}`}>
        {activeView === 'GODDESS' ? (
          <>
            {/* 百花女神：全屏蝴蝶与密集花瓣 */}
            {isHundredFlowers && (
              <>
                <ButterflyOverlay />
                <PetalOverlay type="general" color="#FFD1DC" />
              </>
            )}

            {/* 所有花神共享重构后的细腻粒子系统 */}
            <AtmosphereOverlay 
              type={selectedGoddess.particleType} 
              color={selectedGoddess.color} 
            />

            {/* 十二花神根据属性拥有轻微花瓣 */}
            {!isHundredFlowers && selectedGoddess.particleType !== 'FROST' && (
               <PetalOverlay type="general" color={selectedGoddess.color} />
            )}
          </>
        ) : (
          <AtmosphereOverlay type="HOLY_LIGHT" color="#FFFFFF" />
        )}
      </div>

      <nav className="fixed left-16 top-1/2 -translate-y-1/2 z-50 flex flex-col gap-10">
        {[
          { id: 'ABOUT', label: '造境' },
          { id: 'NOTICE', label: '契约' },
          { id: 'CUSTOM', label: '灵筑' },
          { id: 'CONTACT', label: '传音' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => setActiveInfo(item.id as InfoSection)}
            className="group flex flex-col items-center gap-4 transition-all"
          >
            <span className={`writing-v text-[10px] tracking-[0.6em] transition-all duration-500 ${activeInfo === item.id ? 'text-amber-500' : 'text-white/20 group-hover:text-white'}`}>
              {item.label}
            </span>
            <div className={`w-[1px] transition-all duration-700 ${activeInfo === item.id ? 'h-6 bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.5)]' : 'h-3 bg-white/10 group-hover:h-6 group-hover:bg-white/20'}`} />
          </button>
        ))}
      </nav>

      <main className={`relative z-30 w-full h-full flex items-center pl-44 pr-40 transition-all duration-[1000ms] ${isTransitioning ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}`}>
        {activeView === 'GODDESS' ? (
          <div key={selectedGoddess.id} className="w-full">
            <div className={`transition-all duration-1000 ${showDetail ? 'translate-y-[-40px] scale-90 opacity-20 blur-md' : 'translate-y-0 opacity-100'}`}>
              <div className="flex items-center gap-6 mb-6">
                <div className={`h-[1px] w-16 transition-all duration-1000 ${isHundredFlowers ? 'bg-amber-500/80 w-24' : 'bg-white/20'}`} />
                <span className={`text-[10px] tracking-[0.8em] uppercase font-bold transition-colors duration-1000 ${isHundredFlowers ? 'text-amber-500' : 'text-white/40'}`}>
                  {selectedGoddess.title}
                </span>
              </div>
              <h1 className={`font-brush text-6xl lg:text-8xl tracking-[0.2em] mb-12 transition-all duration-1000 ${isHundredFlowers ? 'text-amber-100 drop-shadow-[0_0_40px_rgba(245,158,11,0.3)]' : 'text-white'}`}>
                {selectedGoddess.name}
              </h1>
              <button 
                onClick={() => setShowDetail(true)}
                className="group flex items-center gap-6 py-4"
              >
                <div className="w-12 h-12 rounded-full border border-white/10 flex items-center justify-center group-hover:border-amber-500/50 transition-all duration-700">
                  <div className="w-1.5 h-1.5 bg-white/30 group-hover:bg-amber-500 group-hover:shadow-[0_0_15px_#f59e0b] rounded-full transition-all" />
                </div>
                <span className="text-[11px] tracking-[0.5em] text-white/30 group-hover:text-white transition-colors">阅 · 芳华录</span>
              </button>
            </div>

            {showDetail && (
              <div className="absolute inset-y-0 left-44 flex flex-col justify-center max-w-2xl animate-fadeIn">
                <div className="flex flex-col gap-10 border-l border-amber-500/30 pl-12 backdrop-blur-xl py-12 pr-12 bg-black/20 rounded-r-3xl">
                  <p className="text-2xl lg:text-3xl font-light text-white/95 leading-relaxed tracking-[0.25em]">
                    {selectedGoddess.shortDesc}
                  </p>
                  <p className="text-base text-white/50 leading-[2.5] tracking-[0.2em] text-justify font-serif">
                    {selectedGoddess.description}
                  </p>
                  <button 
                    onClick={() => setShowDetail(false)}
                    className="mt-8 text-[10px] tracking-[0.6em] text-amber-500/60 hover:text-amber-500 uppercase w-fit border-b border-amber-500/10 hover:border-amber-500 transition-all pb-2"
                  >
                    [ 返回 / CLOSE ]
                  </button>
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="w-full text-center">
             <h1 className="font-brush text-8xl lg:text-[12rem] opacity-10">COMING SOON</h1>
          </div>
        )}
      </main>

      <div className="fixed bottom-14 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center gap-6">
        <div className="flex items-center gap-12 px-14 py-6 bg-white/[0.03] border border-white/10 backdrop-blur-3xl rounded-full shadow-[0_40px_80px_rgba(0,0,0,0.6)]">
          <button 
            onClick={() => handleViewChange('GODDESS')}
            className={`text-[12px] tracking-[0.8em] transition-all duration-700 ${activeView === 'GODDESS' ? 'text-amber-500 font-bold scale-110' : 'text-white/20 hover:text-white/50'}`}
          >
            花神卷
          </button>
          <div className="h-4 w-[1px] bg-white/20" />
          <button 
            onClick={() => handleViewChange('ANGEL')}
            className={`text-[12px] tracking-[0.8em] transition-all duration-700 ${activeView === 'ANGEL' ? 'text-amber-500 font-bold scale-110' : 'text-white/20 hover:text-white/50'}`}
          >
            天使卷
          </button>
        </div>
      </div>

      <InfoOverlay section={activeInfo} onClose={() => setActiveInfo('NONE')} />

      {activeView === 'GODDESS' && (
        <SelectionBar selectedId={selectedGoddess.id} allGoddesses={goddesses} onSelect={handleGoddessChange} />
      )}

      <footer className="fixed bottom-10 left-16 z-40 flex items-center gap-8 pointer-events-auto">
        <button onClick={() => setShowManager(true)} className="flex items-center gap-3 group opacity-20 hover:opacity-100 transition-opacity">
          <span className="text-[9px] tracking-[0.3em] font-bold uppercase">Mapping</span>
        </button>
        <div className="h-4 w-[1px] bg-white/10" />
        <span className="text-[8px] tracking-[0.5em] uppercase text-white/10">Visionary © 2024</span>
      </footer>

      <LocalAssetManager allGoddesses={goddesses} onUpload={updateLocalUrl} isOpen={showManager} onClose={() => setShowManager(false)} />
    </div>
  );
};

export default App;

export type GoddessType = 'HUNDRED' | 'TWELVE';
export type ParticleEffectType = 'GLIMMER' | 'FROST' | 'EMBERS' | 'MIST' | 'FIREFLY' | 'PETALS' | 'STARDUST';

export interface Goddess {
  id: string;
  name: string;
  title: string;
  flower: string;
  description: string;
  shortDesc: string;
  image: string;
  localUrl?: string; 
  pvUrl?: string;    
  shopUrl?: string;  
  color: string;
  type: GoddessType;
  particleType: ParticleEffectType;
}

export interface Particle {
  id: number;
  x: number;
  y: number;
  size: number;
  vx: number;
  vy: number;
  life: number;
  maxLife: number;
  opacity: number;
  color: string;
}

import React, { useEffect, useRef } from 'react';
import { ParticleEffectType } from '../types';

interface Props {
  type: ParticleEffectType;
  color: string;
}

interface RenderParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  life: number;
  maxLife: number;
  noiseOffset: number;
  pulseOffset: number;
  opacity: number;
  rotation: number;
  rotationSpeed: number;
  hueOffset: number;
}

const AtmosphereOverlay: React.FC<Props> = ({ type, color }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particles = useRef<RenderParticle[]>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    const createParticle = (isInitial: boolean = false): RenderParticle => {
      const isFrost = type === 'FROST';
      const isEmbers = type === 'EMBERS';
      const isMist = type === 'MIST';
      const isFirefly = type === 'FIREFLY';

      let vx = (Math.random() - 0.5) * 0.5;
      let vy = Math.random() * 0.3 + 0.1;
      let size = Math.random() * 1.5 + 0.5;

      if (isFrost) {
        vy = Math.random() * 0.8 + 0.3;
        size = Math.random() * 2 + 1;
      } else if (isEmbers) {
        vy = -(Math.random() * 1.2 + 0.4); // 向上飘
        vx = (Math.random() - 0.5) * 1.5;
      } else if (isMist) {
        vy = Math.random() * 0.2 + 0.05;
        size = Math.random() * 40 + 20; // 巨大的模糊雾团
      } else if (isFirefly) {
        vx = (Math.random() - 0.5) * 1.2;
        vy = (Math.random() - 0.5) * 1.2;
        size = Math.random() * 2 + 1;
      }

      return {
        x: Math.random() * canvas.width,
        y: isInitial ? Math.random() * canvas.height : (isEmbers ? canvas.height + 20 : -20),
        vx,
        vy,
        size,
        life: 0,
        maxLife: Math.random() * 1000 + 1000,
        noiseOffset: Math.random() * 10000,
        pulseOffset: Math.random() * Math.PI * 2,
        opacity: Math.random() * 0.5 + 0.2,
        rotation: Math.random() * Math.PI * 2,
        rotationSpeed: (Math.random() - 0.5) * 0.02,
        hueOffset: (Math.random() - 0.5) * 20 // 细微的色调偏移
      };
    };

    // 粒子密度：根据效果调整
    let count = 100;
    if (type === 'STARDUST') count = 250;
    if (type === 'MIST') count = 30;
    if (type === 'FROST') count = 150;
    if (type === 'EMBERS') count = 120;

    particles.current = Array.from({ length: count }, () => createParticle(true));

    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const time = Date.now();

      // 使用 lighter 模式让重叠部分发亮
      ctx.globalCompositeOperation = (type === 'MIST') ? 'source-over' : 'lighter';

      particles.current.forEach((p, i) => {
        p.life++;

        // 核心动力学
        if (type === 'FIREFLY') {
          // 萤火虫：更随意的游动
          p.x += p.vx + Math.sin(time * 0.001 + p.noiseOffset) * 0.8;
          p.y += p.vy + Math.cos(time * 0.001 + p.noiseOffset) * 0.8;
        } else {
          // 常规飘落/上升
          p.y += p.vy;
          p.x += p.vx + Math.sin(time * 0.001 + p.noiseOffset) * 0.4;
        }

        p.rotation += p.rotationSpeed;

        // 边界处理
        if (p.life >= p.maxLife || p.y > canvas.height + 50 || p.y < -50 || p.x > canvas.width + 50 || p.x < -50) {
          particles.current[i] = createParticle(false);
          return;
        }

        // 计算透明度呼吸
        const lifeRatio = 1 - (p.life / p.maxLife);
        const pulse = (Math.sin(time * 0.002 + p.pulseOffset) + 1) / 2;
        let alpha = p.opacity * Math.sin(lifeRatio * Math.PI);

        if (type === 'FIREFLY' || type === 'STARDUST') {
          alpha *= (0.3 + 0.7 * pulse);
        }

        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate(p.rotation);

        if (type === 'MIST') {
          // 绘制雾团
          const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, p.size);
          grad.addColorStop(0, `${color}${Math.floor(alpha * 40).toString(16).padStart(2, '0')}`);
          grad.addColorStop(1, 'transparent');
          ctx.fillStyle = grad;
          ctx.beginPath();
          ctx.arc(0, 0, p.size, 0, Math.PI * 2);
          ctx.fill();
        } else if (type === 'FROST') {
          // 绘制晶体
          ctx.strokeStyle = color;
          ctx.globalAlpha = alpha;
          ctx.lineWidth = 0.5;
          ctx.beginPath();
          ctx.moveTo(-p.size, 0);
          ctx.lineTo(p.size, 0);
          ctx.moveTo(0, -p.size);
          ctx.lineTo(0, p.size);
          ctx.stroke();
          // 中心亮点
          ctx.fillStyle = '#FFFFFF';
          ctx.beginPath();
          ctx.arc(0, 0, p.size * 0.3, 0, Math.PI * 2);
          ctx.fill();
        } else if (type === 'EMBERS') {
          // 绘制火星
          const s = p.size * (1 + pulse);
          ctx.fillStyle = color;
          ctx.shadowBlur = 10;
          ctx.shadowColor = color;
          ctx.globalAlpha = alpha;
          ctx.fillRect(-s/2, -s/2, s, s);
        } else {
          // 默认：细腻星尘
          const s = p.size * (0.8 + 0.4 * pulse);
          ctx.fillStyle = color;
          ctx.globalAlpha = alpha;
          ctx.beginPath();
          ctx.arc(0, 0, s, 0, Math.PI * 2);
          ctx.fill();

          // 增加外发光感
          if (type === 'STARDUST') {
            ctx.globalAlpha = alpha * 0.3;
            ctx.beginPath();
            ctx.arc(0, 0, s * 4, 0, Math.PI * 2);
            ctx.fill();
          }
        }

        ctx.restore();
