import React, { useEffect, useRef } from 'react';

interface Particle {
  x: number;
  y: number;
  size: number;
  speedX: number;
  speedY: number;
  rotation: number;
  rotationSpeed: number;
  flip: number;
  flipSpeed: number;
  opacity: number;
  noiseOffset: number;
}

interface Props {
  type?: 'plum' | 'general' | 'none';
  color?: string;
}

const PetalOverlay: React.FC<Props> = ({ type = 'general', color = '#ffd1dc' }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particles = useRef<Particle[]>([]);

  useEffect(() => {
    if (type === 'none') return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    const particleCount = 50;
    particles.current = Array.from({ length: particleCount }).map(() => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      size: 5 + Math.random() * 8,
      speedX: -0.5 + Math.random() * 1.0,
      speedY: 0.8 + Math.random() * 1.2,
      rotation: Math.random() * Math.PI * 2,
      rotationSpeed: (Math.random() - 0.5) * 0.05,
      flip: Math.random() * Math.PI,
      flipSpeed: 0.03 + Math.random() * 0.03,
      opacity: 0.4 + Math.random() * 0.4,
      noiseOffset: Math.random() * 1000
    }));

    let animationFrame: number;

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const time = Date.now();

      particles.current.forEach(p => {
        // 更新位置
        p.y += p.speedY;
        p.x += p.speedX + Math.sin(time * 0.001 + p.noiseOffset) * 0.5;
        p.rotation += p.rotationSpeed;
        p.flip += p.flipSpeed;

        if (p.y > canvas.height + 20) {
          p.y = -30;
          p.x = Math.random() * canvas.width;
        }

        // 绘制花瓣
        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate(p.rotation);
        // 使用 scale 实现翻转感
        ctx.scale(Math.sin(p.flip), 1);
        ctx.globalAlpha = p.opacity;
        ctx.fillStyle = color;

        ctx.beginPath();
        // 绘制水滴状花瓣
        ctx.moveTo(0, 0);
        ctx.bezierCurveTo(-p.size, -p.size, -p.size, p.size, 0, p.size);
        ctx.bezierCurveTo(p.size, p.size, p.size, -p.size, 0, 0);
        ctx.fill();

        // 增加高光
        ctx.strokeStyle = 'rgba(255,255,255,0.2)';
        ctx.lineWidth = 1;
        ctx.stroke();

        ctx.restore();
      });

      animationFrame = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrame);
    };
  }, [type, color]);

  if (type === 'none') return null;

  return (
    <canvas 
      ref={canvasRef} 
      className="absolute inset-0 pointer-events-none z-20"
    />
  );
};

