      const isFirefly = type === 'FIREFLY';
      const isStardust = type === 'STARDUST';
      const isFrost = type === 'FROST';

      // 差异化初始参数
      let vx = (Math.random() - 0.5) * 0.4;
      let vy = Math.random() * 0.4 + 0.1;
      let size = Math.random() * 1.5 + 0.5;
      let opacity = Math.random() * 0.5 + 0.3;

      if (isEmbers) {
        vy = -(Math.random() * 0.8 + 0.2); // 向上漂浮
        vx = (Math.random() - 0.5) * 0.8;
      } else if (isMist) {
        size = Math.random() * 60 + 40; // 巨大的雾团
        vy = Math.random() * 0.1 + 0.05;
        opacity = Math.random() * 0.15 + 0.05;
      } else if (isFirefly) {
        vx = (Math.random() - 0.5) * 1.5;
        vy = (Math.random() - 0.5) * 1.5;
        size = Math.random() * 2 + 1;
      } else if (isStardust) {
        size = Math.random() * 1.2 + 0.2;
        vy = Math.random() * 0.6 + 0.2;
      }

      return {
        x: Math.random() * canvas.width,
        y: isInitial ? Math.random() * canvas.height : (isEmbers ? canvas.height + 20 : -20),
        vx,
        vy,
        size,
        life: 0,
        maxLife: Math.random() * 1000 + 800,
        noiseOffset: Math.random() * 10000,
        pulseOffset: Math.random() * Math.PI * 2,
        opacity,
        rotation: Math.random() * Math.PI * 2,
        rotationSpeed: (Math.random() - 0.5) * 0.03
      };
    };

    // 针对天使卷 HOLY_LIGHT 保持基础配置
    let count = 120;
    if (type === 'STARDUST') count = 300;
    if (type === 'MIST') count = 40;
    if (type === 'HOLY_LIGHT') count = 80;

    particles.current = Array.from({ length: count }, () => createParticle(true));

    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const time = Date.now();

      // 天使卷使用常规合成，花神卷使用 screen 增强发光
      ctx.globalCompositeOperation = (type === 'HOLY_LIGHT' || type === 'MIST') ? 'source-over' : 'screen';

      particles.current.forEach((p, i) => {
        p.life++;

        // 核心动力学模拟
        if (type === 'FIREFLY') {
          p.x += p.vx + Math.sin(time * 0.002 + p.noiseOffset) * 1.2;
          p.y += p.vy + Math.cos(time * 0.002 + p.noiseOffset) * 1.2;
        } else if (type === 'EMBERS') {
          p.y += p.vy;
          p.x += Math.sin(time * 0.005 + p.noiseOffset) * 1.5; // 火星的不规则抖动
        } else if (type === 'FROST') {
          p.y += p.vy * 1.5;
          p.x += Math.sin(time * 0.001 + p.noiseOffset) * 0.2;
        } else {
          p.y += p.vy;
          p.x += p.vx + Math.sin(time * 0.001 + p.noiseOffset) * 0.4;
        }

        p.rotation += p.rotationSpeed;

        if (p.life >= p.maxLife || p.y > canvas.height + 60 || p.y < -60) {
          particles.current[i] = createParticle(false);
          return;
        }

        const lifeRatio = Math.sin((p.life / p.maxLife) * Math.PI);
        const pulse = (Math.sin(time * 0.003 + p.pulseOffset) + 1) / 2;
        let alpha = p.opacity * lifeRatio;

        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate(p.rotation);

        if (type === 'MIST') {
          const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, p.size);
          grad.addColorStop(0, `${color}${Math.floor(alpha * 255).toString(16).padStart(2, '0')}`);
          grad.addColorStop(1, 'transparent');
          ctx.fillStyle = grad;
          ctx.beginPath();
          ctx.arc(0, 0, p.size, 0, Math.PI * 2);
          ctx.fill();
        } else if (type === 'FROST') {
          // 冰晶晶体感
          ctx.strokeStyle = color;
          ctx.globalAlpha = alpha;
          ctx.lineWidth = 1;
          ctx.beginPath();
          ctx.moveTo(-p.size, 0); ctx.lineTo(p.size, 0);
          ctx.moveTo(0, -p.size); ctx.lineTo(0, p.size);
          ctx.stroke();
          ctx.fillStyle = '#fff';
          ctx.beginPath();
          ctx.arc(0, 0, p.size * 0.3, 0, Math.PI * 2);
          ctx.fill();
        } else if (type === 'EMBERS') {
          // 火星：高亮中心
          const s = p.size * (0.8 + 0.4 * pulse);
          ctx.shadowBlur = 10;
          ctx.shadowColor = color;
          ctx.fillStyle = color;
          ctx.globalAlpha = alpha;
          ctx.fillRect(-s/2, -s/2, s, s);
        } else if (type === 'HOLY_LIGHT') {
          // 天使卷：保持最简单的光点，不做过度设计
          ctx.fillStyle = color;
          ctx.globalAlpha = alpha * 0.5;
          ctx.beginPath();
          ctx.arc(0, 0, p.size, 0, Math.PI * 2);
          ctx.fill();
        } else {
          // 常规与百花：细腻星尘
          const s = p.size * (0.6 + 0.4 * pulse);
          ctx.fillStyle = color;
          ctx.globalAlpha = alpha;
          // Fix: isStardust was not defined in this scope, use the 'type' prop instead.
          ctx.shadowBlur = type === 'STARDUST' ? 15 : 5;
          ctx.shadowColor = color;
          ctx.beginPath();
          ctx.arc(0, 0, s, 0, Math.PI * 2);
          ctx.fill();

          // Fix: isStardust was not defined in this scope, use the 'type' prop instead.
          if (type === 'STARDUST') {
            // 为百花女神增加细微拖尾感
            ctx.globalAlpha = alpha * 0.3;
            ctx.beginPath();
            ctx.arc(-p.vx * 10, -p.vy * 10, s * 0.8, 0, Math.PI * 2);
            ctx.fill();
          }
        }
        ctx.restore();
      });

      animationFrame = requestAnimationFrame(render);
    };

    render();
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrame);
    };
  }, [type, color]);

  return <canvas ref={canvasRef} className="absolute inset-0 pointer-events-none z-20" />;
};

export default AtmosphereOverlay;
